# Output CSV file
OUTPUT_FILE="/tmp/TRITON-35127-reach_data.csv"

# Loop through the array of URLs
for url in "${urls[@]}"
do
    echo "Checking Source Reach ${url}"
    response=$(curl -s -X POST "https://reach-service-hybrid-prod-internal.meltwater.io/v1/query" \
    -H "Content-Type: application/json" \
    -H "X-Client-Name: node-support-scripts" \
    -d "{\"url\": \"$url\", \"checkOnlyLocal\": false}")
 
# Extract the desktopVisitors and mobileVisitors from the response using jq
    desktopVisitors=$(echo "$response" | jq -r '.desktopVisitors // 0')
    mobileVisitors=$(echo "$response" | jq -r '.mobileVisitors // 0')

 #Append the URL and visitors data to the CSV file, echo the response for debugging
    echo "\"$url\",$desktopVisitors,$mobileVisitors" >> "$OUTPUT_FILE"
    echo "$response"
    sleep 1
done